32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PROCESSING_FEE = 5;
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	
49	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
54	
55	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
56	
57	const DEDUCTIBLE = 100;
58	const PAYOUT_CAP_MULTIPLIER = 2;
59	
60	const HIGH_ENCHANTMENT_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
62	const FULL_REIMBURSEMENT_RATE = 1;
63	
64	const INSURANCE_VALUES: Record<string, number> = {
65	  sword: 1000,
66	  amulet: 600,
67	  staff: 800,
68	  potion: 400,
69	  rune: 250,
70	  moonstone: 250,
71	};
72	
73	const countItemsByType = (items: Item[]): Map<string, number> => {
74	  const counts = new Map<string, number>();
75	  for (const item of items) {
76	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
77	  }
78	  return counts;
79	};
80	
81	const basePremiumForGroup = (type: string, count: number): number =>
82	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
83	
84	const calculateTotalBasePremium = (items: Item[]): number =>
85	  [...countItemsByType(items)].reduce(
86	    (total, [type, count]) => total + basePremiumForGroup(type, count),
87	    0,
88	  );
89	
90	const curseSurchargeForItem = (item: Item): number =>
91	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
92	
93	const enchantmentSurchargeForItem = (item: Item): number =>
94	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
95	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
96	    : 0;
97	
98	const sumSurcharges = (
99	  items: Item[],
100	  surchargeForItem: (item: Item) => number,
101	): number =>
102	  items.reduce((total, item) => total + surchargeForItem(item), 0);
103	
104	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
105	  const loyaltyDiscountRate =
106	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
107	      ? LOYALTY_DISCOUNT_RATE
108	      : 0;
109	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
110	  return loyaltyDiscountRate + followUpDiscountRate;
111	};
112	
113	const payoutCapForItems = (items: Item[]): number =>
114	  PAYOUT_CAP_MULTIPLIER *
115	  items.reduce((total, item) => total + INSURANCE_VALUES[item.type], 0);
116	
117	const reimbursementRateForItem = (item: Item | undefined): number =>
118	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
119	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
120	    : FULL_REIMBURSEMENT_RATE;
121	
122	const reimbursementForDamage = (
123	  damage: Damage,
124	  policyItems: Item[],
125	): number => {
126	  const damagedItem = policyItems.find(
127	    (item) => item.type === damage.itemType,
128	  );
129	  return damage.amount * reimbursementRateForItem(damagedItem);
130	};
131	
132	const processClaimStep = (step: ClaimStep, steps: Step[]): ClaimResult => {
133	  const policyItems = (steps[step.policy] as QuoteStep).items;
134	  const payoutCap = payoutCapForItems(policyItems);
135	  const damage = step.incident.damages[0];
136	  const payout = reimbursementForDamage(damage, policyItems) - DEDUCTIBLE;
137	  return {
138	    payout,
139	    remainingCap: payoutCap - payout,
140	  };
141	};
142	
143	const processQuoteStep = (
144	  step: QuoteStep,
145	  customer: Customer,
146	  stepIndex: number,
147	): QuoteResult => {
148	  const totalBasePremium = calculateTotalBasePremium(step.items);
149	  const firstInsuranceSurcharge =
150	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
151	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
152	  const enchantmentSurcharge = sumSurcharges(
153	    step.items,
154	    enchantmentSurchargeForItem,
155	  );
156	  const discount =
157	    totalBasePremium * policyDiscountRate(customer, stepIndex);
158	  return {
159	    premium: Math.ceil(
160	      totalBasePremium + firstInsuranceSurcharge + curseSurcharge +
161	        enchantmentSurcharge - discount + PROCESSING_FEE,
162	    ),
163	  };
164	};
165	
166	export const processScenario = (scenario: Scenario): ScenarioResult => ({
167	  results: scenario.steps.map((step, index) =>
168	    "incident" in step
169	      ? processClaimStep(step, scenario.steps)
170	      : processQuoteStep(step, scenario.customer, index),
171	  ),
172	});
